const e=JSON.parse('{"key":"v-22595457","path":"/posts/%E4%BB%8E%E6%B5%8F%E8%A7%88%E5%99%A8%E6%B8%B2%E6%9F%93%E8%AE%B2%E6%80%A7%E8%83%BD%E4%BC%98%E5%8C%96.html","title":"从浏览器渲染讲性能优化","lang":"zh-CN","frontmatter":{"title":"从浏览器渲染讲性能优化","isTimeLine":true,"date":"2026-03-12T00:00:00.000Z","category":["前端"],"tag":["性能优化","浏览器原理"]},"headers":[],"git":{"createdTime":1773252729000,"updatedTime":1773252729000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":6.67,"words":2002},"filePathRelative":"posts/从浏览器渲染讲性能优化.md","localizedDate":"2026年3月12日","excerpt":"<h4> 进程与线程</h4>\\n<ol>\\n<li>进程: 一个程序，浏览器打开一个页面就开辟一个进程。是资源分配的最小单位。</li>\\n<li>线程：程序中具体“干活”的人，浏览器具备很多线程。是CPU调度的最小单位。</li>\\n<li>一个进程中由一个或多个线程组成，同个进程内的线程之间共享进程的数据。进程之间的内容互相隔离，数据是不能直接共享的。这样就算一个进程挂起或者崩溃也不会影响影响其他进程。</li>\\n<li>js是单线程执行的。作为浏览器脚本语言，JavaScript的主要用途是与用户互动，以及操作DOM。这决定了它只能是单线程，否则会带来很复杂的同步问题。</li>\\n<li>打开一个网页，最少需要四个进程：<code>浏览器主进程</code>（负责界面显示、用户交互、子进程管理等）、<code>网络进程</code>（负责网络资源的加载）、<code>GPU进程</code>（UI界面的绘制）、<code>渲染进程</code>（将 HTML、CSS 和 JavaScript转换成网页）。</li>\\n</ol>"}');export{e as data};
